// Compute past N business days (excluding weekends) ending today (CST).
const N = 7;
const central = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Chicago' });
const [y, m, d] = central.split('-').map(Number);
const end = new Date(y, m - 1, d);
const dates = [];
const cur = new Date(end);
while (dates.length < N) {
  const day = cur.getDay();
  if (day !== 0 && day !== 6) {
    const ds = cur.getFullYear() + '-' + String(cur.getMonth() + 1).padStart(2, '0') + '-' + String(cur.getDate()).padStart(2, '0');
    dates.push(ds);
  }
  cur.setDate(cur.getDate() - 1);
}
dates.reverse();
return [{ json: { backfillDates: dates } }];

const runStatus = $input.first().json;
const datasetId = runStatus?.data?.defaultDatasetId;
const runId = runStatus?.data?.id || 'unknown';
if (!datasetId) {
  return [{ json: { error: true, message: 'No defaultDatasetId. runId=' + runId } }];
}
const token = 'YOUR_APIFY_TOKEN';
const url = `https://api.apify.com/v2/datasets/${datasetId}/items?token=${token}`;
const raw = await this.helpers.httpRequest({ method: 'GET', url, encoding: 'utf-8', returnFullResponse: false, timeout: 60000, headers: { Accept: 'application/json' } });
let items = raw;
if (typeof raw === 'string') { try { items = JSON.parse(raw); } catch (e) { return [{ json: { error: true, message: 'JSON parse failed: ' + raw.substring(0,200) } }]; } }
if (!Array.isArray(items) || items.length === 0) {
  return [{ json: { error: true, message: 'Empty dataset for runId=' + runId, datasetId } }];
}
const backfills = items.filter((i) => i._type === 'sale_made_backfill');
return [{ json: { backfills, runId, datasetId, count: backfills.length } }];

// Split each backfill item into its own n8n item so the next HTTP node fans out per date.
const backfills = $json.backfills || [];
return backfills.map((b) => ({ json: { scrape_date: b.scrape_date, agents: b.agents || [], mode: 'sales_only' } }));

// Build a Slack summary of all backfilled dates and any deltas detected.
const items = $input.all().map((i) => i.json);
let totalUpdated = 0;
let totalInserted = 0;
let totalAgents = 0;
const lines = [];
for (const r of items) {
  if (!r) continue;
  const date = r.scrape_date || 'unknown';
  const updated = r.sales_only_updated || 0;
  const inserted = r.sales_only_inserted || 0;
  const ups = r.upserted || 0;
  totalUpdated += updated;
  totalInserted += inserted;
  totalAgents += ups;
  lines.push(`• *${date}* — ${ups} agents (updated: ${updated}, inserted: ${inserted})`);
}
const now = new Date();
const centralStr = now.toLocaleString('en-US', { timeZone: 'America/Chicago', hour: 'numeric', minute: '2-digit', hour12: true });
const message = {
  text: `DSB sales late sweep complete (${items.length} dates)`,
  blocks: [
    { type: 'header', text: { type: 'plain_text', text: ':arrows_counterclockwise: DSB Sales Late Sweep', emoji: true } },
    { type: 'section', text: { type: 'mrkdwn', text: `*Sweep run at ${centralStr} CST*\n${items.length} dates re-scraped (Sale Made only)\n*Total:* ${totalAgents} agents | ${totalUpdated} updated | ${totalInserted} inserted` } },
    { type: 'divider' },
    { type: 'section', text: { type: 'mrkdwn', text: lines.join('\n') || '_No data_' } },
    { type: 'context', elements: [{ type: 'mrkdwn', text: 'Sales-only mode preserves dials/talk/leads. Catches sales entered after the daily scrape ran.' }] }
  ]
};
return [{ json: message }];
